-- Ads table: hottest query path (list by campaign, filter by status)
CREATE INDEX IF NOT EXISTS ads_campaignId_idx ON ads (campaignId);
CREATE INDEX IF NOT EXISTS ads_campaignId_status_idx ON ads (campaignId, status);
CREATE INDEX IF NOT EXISTS ads_campaignId_createdAt_idx ON ads (campaignId, createdAt);
CREATE INDEX IF NOT EXISTS ads_userId_idx ON ads (userId);

-- Evaluations: looked up by adId and by campaign
CREATE INDEX IF NOT EXISTS evaluations_adId_idx ON evaluations (adId);
CREATE INDEX IF NOT EXISTS evaluations_campaignId_idx ON evaluations (campaignId);

-- Campaigns: looked up by userId
CREATE INDEX IF NOT EXISTS campaigns_userId_idx ON campaigns (userId);
CREATE INDEX IF NOT EXISTS campaigns_status_idx ON campaigns (status);

-- Iteration logs: looked up by campaign
CREATE INDEX IF NOT EXISTS iteration_logs_campaignId_idx ON iteration_logs (campaignId);
CREATE INDEX IF NOT EXISTS iteration_logs_adId_idx ON iteration_logs (adId);

-- Adversarial sessions
CREATE INDEX IF NOT EXISTS adversarial_sessions_campaignId_idx ON adversarial_sessions (campaignId);

-- Creative spark ideas
CREATE INDEX IF NOT EXISTS creative_spark_ideas_campaignId_idx ON creative_spark_ideas (campaignId);

